SELECT 
,role_manage_id.id as role_manage_id_id1
,role_manage_id.role_name as role_manage_id_role_name1
FROM sys_user su
left join role_manage role_manage_id on role_manage_id.id=su.role_manage_id
where 1 = 1
  and su.id = #{id}  
  and su.USERNAME = #{USERNAME}  
  and su.PASSWORD = #{PASSWORD}  
  and su.NAME = #{NAME}  
  and su.role_manage_id = #{role_manage_id}  
  and su.create_time = #{create_time}  
  and su.update_time = #{update_time}  
  and su.signature = #{signature}  
  and su.account_status = #{account_status}

